import React, { useState, useRef } from 'react';
import { useAppStore } from '../services/store';
import { User, Role } from '../types';
import { Shield, BookOpen, Calculator, UserCheck, Lock, Mail, User as UserIcon, TestTube, Check, FileSpreadsheet, Upload, Info } from 'lucide-react';
import { createUserWithEmailAndPassword, signInWithEmailAndPassword } from 'firebase/auth';
import { auth } from '../services/firebase';

const Auth: React.FC = () => {
  const { state, dispatch } = useAppStore();
  const [isLogin, setIsLogin] = useState(true);

  // Login State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  // Register State
  const [regForm, setRegForm] = useState<Partial<User>>({
    name: '', email: '', role: 'student', phone: '', address: '',
    classId: '', section: '', annualFee: 0, discount: 0, subjects: [], password: ''
  });
  const [regSuccess, setRegSuccess] = useState('');

  // Bulk Registration State
  const [bulkFile, setBulkFile] = useState<File | null>(null);
  const [bulkClass, setBulkClass] = useState('');
  const [isProcessingBulk, setIsProcessingBulk] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    try {
        await signInWithEmailAndPassword(auth, email, password);
        const user = state.users.find(u => u.email.toLowerCase() === email.toLowerCase());

        if (user) {
            if (user.status !== 'active' && user.role !== 'developer') {
                setError('Your account is pending approval by an administrator.');
                return;
            }
            dispatch({ type: 'LOGIN', payload: user });
        } else {
            setError('User profile not found in database.');
        }

    } catch (firebaseError: any) {
        const user = state.users.find(u => u.email.toLowerCase() === email.toLowerCase());
        if (user && user.password === password) {
            if (user.status !== 'active') {
                setError('Your account is pending approval by an administrator.');
                return;
            }
            dispatch({ type: 'LOGIN', payload: user });
        } else {
            setError(firebaseError.code === 'auth/invalid-credential' ? 'Invalid credentials' : 'Login failed: ' + firebaseError.message);
        }
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!regForm.password || regForm.password.length < 6) {
        setError('Password must be at least 6 characters long.');
        return;
    }

    try {
        const userCredential = await createUserWithEmailAndPassword(auth, regForm.email!, regForm.password);
        const uid = userCredential.user.uid;

        const newUser: User = {
            id: uid,
            name: regForm.name || '',
            email: regForm.email || '',
            role: regForm.role as Role,
            allowedRoles: [regForm.role as Role],
            password: regForm.password,
            status: regForm.role === 'developer' ? 'active' : 'pending',
            phone: regForm.phone,
            address: regForm.address,
            annualFee: 0, 
            discount: 0,
            totalPaid: 0,
            ...(regForm.role === 'student' && regForm.classId ? { classId: regForm.classId } : {}),
            ...(regForm.role === 'student' && regForm.section ? { section: regForm.section } : {}),
            ...(regForm.role === 'teacher' && regForm.subjects ? { subjects: regForm.subjects } : {})
        };

        dispatch({ type: 'ADD_USER', payload: newUser });
        setRegSuccess(regForm.role === 'developer' ? 'Developer Account Created! Please Login.' : 'Registration submitted. Please wait for approval.');
        setRegForm({ name: '', email: '', role: 'student', phone: '', address: '', classId: '', section: '', annualFee: 0, discount: 0, subjects: [], password: '' });

        setTimeout(() => {
            setRegSuccess('');
            setIsLogin(true);
        }, 3000);

    } catch (err: any) {
        if (err.code === 'auth/email-already-in-use') {
            setError('This email is already registered.');
        } else {
            setError(err.message || 'Registration failed.');
        }
    }
  };

  const handleBulkUpload = async () => {
      if (!bulkFile || !bulkClass) {
          setError('Please select a file and a class.');
          return;
      }

      setIsProcessingBulk(true);
      setError('');

      const reader = new FileReader();
      reader.onload = async (e) => {
          const text = e.target?.result as string;
          const lines = text.split('\n');
          let count = 0;

          // Skip header if it exists (assuming Name,Email,Password)
          const startIdx = (lines[0].toLowerCase().includes('name') || lines[0].toLowerCase().includes('email')) ? 1 : 0;

          for (let i = startIdx; i < lines.length; i++) {
              const line = lines[i].trim();
              if (!line) continue;

              const [name, email, password] = line.split(',').map(s => s.trim());
              if (name && email && password) {
                  const newUser: User = {
                      id: `bulk_${Date.now()}_${i}`,
                      name,
                      email: email.toLowerCase(),
                      password,
                      role: 'student',
                      allowedRoles: ['student'],
                      status: 'pending',
                      classId: bulkClass,
                      totalPaid: 0,
                      annualFee: 0,
                      discount: 0
                  };
                  dispatch({ type: 'ADD_USER', payload: newUser });
                  count++;
              }
          }

          setRegSuccess(`Successfully queued ${count} students for approval.`);
          setBulkFile(null);
          setRegForm(prev => ({ ...prev, email: '' })); // Clear the trigger
          setIsProcessingBulk(false);

          setTimeout(() => {
              setRegSuccess('');
              setIsLogin(true);
          }, 3000);
      };

      reader.readAsText(bulkFile);
  };

  const toggleSubject = (subjectName: string) => {
      const currentSubjects = regForm.subjects || [];
      if (currentSubjects.includes(subjectName)) {
          setRegForm({ ...regForm, subjects: currentSubjects.filter(s => s !== subjectName) });
      } else {
          setRegForm({ ...regForm, subjects: [...currentSubjects, subjectName] });
      }
  };

  const selectedClassData = state.systemClasses.find(c => c.name === regForm.classId);
  const isBulkMode = regForm.email?.toLowerCase() === 'bulkregister';

  return (
    <div className="min-h-screen bg-gradient-to-br from-galaxy-900 via-galaxy-800 to-galaxy-600 flex items-center justify-center p-4">
      <div className="bg-white rounded-2xl shadow-2xl p-8 max-w-4xl w-full flex flex-col md:flex-row gap-8">

        <div className="md:w-1/3 flex flex-col justify-center border-r border-gray-100 pr-8">
            <div className="w-16 h-16 bg-gold-400 rounded-xl flex items-center justify-center text-galaxy-900 font-bold text-3xl mb-6">
                G
            </div>
            <h1 className="text-3xl font-bold text-galaxy-900 mb-2">Galaxy Hotel</h1>
            <h2 className="text-xl font-medium text-galaxy-600 mb-6">& Tourism School</h2>
            <p className="text-gray-500 text-sm leading-relaxed">
                Welcome to the official portal. Manage assignments, examinations, fees, and more with our integrated role-based system.
            </p>
            <div className="mt-8 pt-6 border-t border-gray-100">
                <p className="text-xs text-gray-400">System Version 2.0.0</p>
            </div>
        </div>

        <div className="md:w-2/3">
            <div className="flex justify-between items-center mb-6">
                <h3 className="text-2xl font-bold text-gray-800">{isLogin ? 'Sign In' : isBulkMode ? 'Bulk Enrollment' : 'Create Account'}</h3>
                <button 
                    onClick={() => { setIsLogin(!isLogin); setError(''); setRegSuccess(''); }}
                    className="text-sm text-galaxy-600 font-semibold hover:underline"
                >
                    {isLogin ? 'Need an account?' : 'Already have an account?'}
                </button>
            </div>

            {error && <div className="bg-red-50 text-red-600 p-3 rounded mb-4 text-sm flex items-center gap-2"><Lock size={16}/> {error}</div>}
            {regSuccess && <div className="bg-green-50 text-green-600 p-3 rounded mb-4 text-sm flex items-center gap-2"><Check size={16}/> {regSuccess}</div>}

            {isLogin ? (
                <>
                <form onSubmit={handleLogin} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Email Address</label>
                        <div className="relative">
                            <Mail className="absolute left-3 top-2.5 text-gray-400" size={18} />
                            <input 
                                type="email" 
                                className="w-full border pl-10 p-2 rounded-lg focus:ring-2 focus:ring-galaxy-500 outline-none"
                                value={email}
                                onChange={e => setEmail(e.target.value)}
                                placeholder="name@galaxy.edu.np"
                                required
                            />
                        </div>
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Password</label>
                        <div className="relative">
                            <Lock className="absolute left-3 top-2.5 text-gray-400" size={18} />
                            <input 
                                type="password" 
                                className="w-full border pl-10 p-2 rounded-lg focus:ring-2 focus:ring-galaxy-500 outline-none"
                                value={password}
                                onChange={e => setPassword(e.target.value)}
                                placeholder="••••••••"
                                required
                            />
                        </div>
                    </div>
                    <button type="submit" className="w-full bg-galaxy-900 text-white py-3 rounded-lg hover:bg-galaxy-800 font-bold shadow-lg transform transition active:scale-95">
                        Login to Portal
                    </button>
                </form>

                {(email === 'opentesting' || email === 'bulkregister') && (
                    <div className="mt-8 pt-6 border-t border-gray-100 animate-in fade-in slide-in-from-top-2">
                        <label className="block text-xs font-bold text-red-500 uppercase mb-2 flex items-center gap-1">
                            <TestTube size={14} /> Secret Mode
                        </label>
                        {email === 'opentesting' ? (
                            <select
                                className="w-full text-sm border border-red-200 bg-red-50 text-red-800 rounded-lg p-2.5 focus:outline-none focus:ring-2 focus:ring-red-300"
                                onChange={(e) => {
                                    const selectedEmail = e.target.value;
                                    if(!selectedEmail) return;
                                    const user = state.users.find(u => u.email === selectedEmail);
                                    if(user) dispatch({ type: 'LOGIN', payload: user });
                                }}
                                defaultValue=""
                            >
                                <option value="" disabled>-- Quick Login As Role --</option>
                                <option value="admin@galaxy.edu.np">Admin (Super Admin)</option>
                                <option value="ramesh@galaxy.edu.np">Accountant (Ramesh Adhikari)</option>
                                <option value="sarita@galaxy.edu.np">Teacher (Sarita Sharma)</option>
                                <option value="ram@galaxy.edu.np">Student (Ram Kafle)</option>
                                <option value="dheejan@gmail.com">Developer</option>
                            </select>
                        ) : (
                            <button 
                                onClick={() => { setIsLogin(false); setRegForm({...regForm, email: 'bulkregister'}); }}
                                className="w-full bg-galaxy-100 text-galaxy-900 py-2 rounded-lg font-bold flex items-center justify-center gap-2 hover:bg-galaxy-200"
                            >
                                <FileSpreadsheet size={18}/> Go to Bulk Enrollment Mode
                            </button>
                        )}
                    </div>
                )}
                </>
            ) : isBulkMode ? (
                <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-300">
                    <div className="bg-galaxy-50 p-4 rounded-xl border border-galaxy-100">
                        <h4 className="font-bold text-galaxy-900 flex items-center gap-2 mb-2">
                            <Info size={18} className="text-galaxy-600"/> CSV Instructions
                        </h4>
                        <p className="text-xs text-gray-600 leading-relaxed">
                            Upload a CSV file with 3 columns: <code className="bg-white px-1 border rounded">Full Name, Email, Password</code>.
                            Passwords must be at least 6 characters. Headers are allowed but optional.
                        </p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Target Class</label>
                            <select 
                                className="w-full border p-2 rounded-lg bg-white"
                                value={bulkClass}
                                onChange={e => setBulkClass(e.target.value)}
                            >
                                <option value="">-- Choose Class --</option>
                                {state.systemClasses.map(cls => (
                                    <option key={cls.name} value={cls.name}>{cls.name}</option>
                                ))}
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">CSV File</label>
                            <input 
                                type="file" 
                                accept=".csv"
                                className="hidden"
                                ref={fileInputRef}
                                onChange={e => setBulkFile(e.target.files?.[0] || null)}
                            />
                            <button 
                                onClick={() => fileInputRef.current?.click()}
                                className="w-full border-2 border-dashed border-gray-300 p-2 rounded-lg text-sm text-gray-500 hover:border-galaxy-400 hover:text-galaxy-600 transition-colors flex items-center justify-center gap-2"
                            >
                                <Upload size={16}/> {bulkFile ? bulkFile.name : 'Select CSV File'}
                            </button>
                        </div>
                    </div>

                    <div className="flex gap-3">
                        <button 
                            onClick={() => { setRegForm({...regForm, email: ''}); setBulkFile(null); }}
                            className="flex-1 py-3 border rounded-lg text-gray-600 font-bold hover:bg-gray-50"
                        >
                            Cancel
                        </button>
                        <button 
                            onClick={handleBulkUpload}
                            disabled={!bulkFile || !bulkClass || isProcessingBulk}
                            className="flex-1 py-3 bg-galaxy-900 text-white rounded-lg font-bold shadow-lg hover:bg-galaxy-800 disabled:opacity-50 flex items-center justify-center gap-2"
                        >
                            {isProcessingBulk ? 'Processing...' : 'Upload & Enroll'}
                        </button>
                    </div>
                </div>
            ) : (
                <form onSubmit={handleRegister} className="space-y-3 h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                     <div>
                        <label className="block text-sm font-medium text-gray-700">Account Type</label>
                        <select 
                            className="w-full border p-2 rounded mt-1 bg-gray-50"
                            value={regForm.role}
                            onChange={e => setRegForm({...regForm, role: e.target.value as Role})}
                            required
                        >
                            <option value="student">Student</option>
                            <option value="intern">Intern</option>
                            <option value="teacher">Teacher</option>
                            <option value="accountant">Accountant</option>
                            <option value="admin">Admin</option>
                        </select>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                         <div>
                            <label className="block text-sm font-medium text-gray-700">Full Name</label>
                            <input 
                                type="text" required
                                className="w-full border p-2 rounded mt-1"
                                value={regForm.name}
                                onChange={e => setRegForm({...regForm, name: e.target.value})}
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Email</label>
                            <input 
                                type="email" required
                                className="w-full border p-2 rounded mt-1"
                                value={regForm.email}
                                onChange={e => {
                                    setRegForm({...regForm, email: e.target.value});
                                    if(e.target.value.toLowerCase() === 'bulkregister') {
                                        setError('');
                                    }
                                }}
                                placeholder="name@galaxy.edu.np"
                            />
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                         <div>
                            <label className="block text-sm font-medium text-gray-700">Phone</label>
                            <input 
                                type="text"
                                className="w-full border p-2 rounded mt-1"
                                value={regForm.phone}
                                onChange={e => setRegForm({...regForm, phone: e.target.value})}
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Set Password</label>
                            <input 
                                type="password" required
                                className="w-full border p-2 rounded mt-1"
                                value={regForm.password}
                                onChange={e => setRegForm({...regForm, password: e.target.value})}
                                minLength={6}
                                placeholder="Min 6 chars"
                            />
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Address</label>
                        <input 
                            type="text"
                            className="w-full border p-2 rounded mt-1"
                            value={regForm.address}
                            onChange={e => setRegForm({...regForm, address: e.target.value})}
                        />
                    </div>

                     {regForm.role === 'student' && (
                        <div className="bg-blue-50 p-3 rounded-lg border border-blue-100 space-y-2">
                            <h4 className="font-semibold text-blue-800 text-xs uppercase">Student Details</h4>
                            <div className="grid grid-cols-2 gap-2">
                                <div>
                                    <label className="block text-xs font-medium text-gray-700">Class / Batch</label>
                                    <select 
                                        required
                                        className="w-full border p-2 rounded mt-1 text-sm bg-white"
                                        value={regForm.classId}
                                        onChange={e => setRegForm({...regForm, classId: e.target.value, section: ''})}
                                    >
                                        <option value="">-- Select Class --</option>
                                        {state.systemClasses.map(cls => (
                                            <option key={cls.name} value={cls.name}>{cls.name}</option>
                                        ))}
                                    </select>
                                </div>
                                {selectedClassData && selectedClassData.sections.length > 0 && (
                                    <div>
                                        <label className="block text-xs font-medium text-gray-700">Section</label>
                                        <select 
                                            required
                                            className="w-full border p-2 rounded mt-1 text-sm bg-white"
                                            value={regForm.section}
                                            onChange={e => setRegForm({...regForm, section: e.target.value})}
                                        >
                                            <option value="">-- Select Section --</option>
                                            {selectedClassData.sections.map(sec => (
                                                <option key={sec} value={sec}>{sec}</option>
                                            ))}
                                        </select>
                                    </div>
                                )}
                            </div>
                        </div>
                    )}

                    {regForm.role === 'teacher' && (
                        <div className="bg-purple-50 p-3 rounded-lg border border-purple-100">
                            <h4 className="font-semibold text-purple-800 text-xs uppercase mb-2">Select Subjects</h4>
                            <div className="flex flex-wrap gap-2">
                                {state.availableSubjects.map(subject => {
                                    const isSelected = regForm.subjects?.includes(subject.name);
                                    return (
                                        <button
                                            key={subject.name}
                                            type="button"
                                            onClick={() => toggleSubject(subject.name)}
                                            className={`text-xs px-2 py-1 rounded-full border transition-all ${
                                                isSelected 
                                                ? 'bg-purple-600 text-white border-purple-600' 
                                                : 'bg-white text-gray-600 border-gray-300 hover:border-purple-400'
                                            }`}
                                        >
                                            {subject.name} {isSelected && '✓'}
                                        </button>
                                    )
                                })}
                            </div>
                        </div>
                    )}

                    <button type="submit" className="w-full bg-galaxy-600 text-white py-2 rounded-lg hover:bg-galaxy-700 font-semibold shadow-sm mt-4">
                        Register Account
                    </button>
                </form>
            )}
        </div>

      </div>
    </div>
  );
};

export default Auth;
